directUploadPattern.codeExample:
// Upload file to File Service
const uploadFile = async (file: File, accessToken: string) => {
  const formData = new FormData();
  formData.append('file', file);
  formData.append('type', 'application-document');

  const response = await fetch(`${fileServiceUrl}/file/v1/files`, {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${accessToken}` },
    body: formData
  });

  const { urn } = await response.json();
  return urn; // e.g., 'urn:ads:platform:file-service:v1:/files/abc123'
};

