// Download file by URN
const downloadFile = async (fileUrn: string, accessToken: string) => {
  const fileId = fileUrn.split('/files/')[1];
  const response = await fetch(`${fileServiceUrl}/file/v1/files/${fileId}/download`, {
    headers: { 'Authorization': `Bearer ${accessToken}` }
  });
  return response.blob();
};
